import { Injectable } from '@nestjs/common';
import * as bcrypt from 'bcrypt';

/**
 * Password hashing (README §2.5 A02). bcrypt cost factor 12. Passwords are never
 * compared with `===` and never stored/logged in plain or base64 form.
 */
@Injectable()
export class PasswordService {
  private static readonly COST = 12;

  hash(plain: string): Promise<string> {
    return bcrypt.hash(plain, PasswordService.COST);
  }

  verify(plain: string, hash: string): Promise<boolean> {
    return bcrypt.compare(plain, hash);
  }
}
